import scala.collection.mutable

object Dijkstra {

  // Function to calculate shortest path using Dijkstra's algorithm
  def dijkstra(edges: List[Edge], numVertices: Int, startNode: Int): Array[Int] = {
    val distances = Array.fill(numVertices)(Int.MaxValue)
    distances(startNode) = 0
    val unvisitedNodes = mutable.PriorityQueue[(Int, Int)]((startNode, 0))(Ordering.by(_._2).reverse)

    while (unvisitedNodes.nonEmpty) {
      val (currentNode, currentDistance) = unvisitedNodes.dequeue()

      if (distances(currentNode) == currentDistance) {
        for (edge <- edges.filter(_.src == currentNode)) {
          val newDistance = currentDistance + edge.weight
          if (newDistance < distances(edge.dest)) {
            distances(edge.dest) = newDistance
            unvisitedNodes.enqueue((edge.dest, newDistance))
          }
        }
      }
    }

    distances
  }
}

