const fs = require('fs');
const path = require('path');
const csvParser = require('csv-parser');
const axios = require('axios');
const crypto = require('crypto');

async function downloadAndSavePage(url) {
  try {
    const response = await axios.get(url);
    const content = response.data;
    const hash = crypto.createHash('sha256').update(content).digest('hex');
    const filePath = path.join(__dirname, `${hash}.txt`);

    fs.writeFileSync(filePath, content);

    console.log(`Downloaded and saved ${url} as ${hash}.txt`);
  } catch (error) {
    console.error(`Failed to download ${url}: ${error.message}`);
  }
}

function readUrlsFromCsv(csvFilePath) {
  return new Promise((resolve, reject) => {
    const urls = [];

    fs.createReadStream(csvFilePath)
      .pipe(csvParser())
      .on('data', (row) => {
        if (row.url) {
          urls.push(row.url);
        }
      })
      .on('end', () => {
        resolve(urls);
      })
      .on('error', (error) => {
        reject(error);
      });
  });
}

async function main() {
  const csvFilePath = path.join(__dirname, 'urls.csv');

  try {
    const urls = await readUrlsFromCsv(csvFilePath);

    for (const url of urls) {
      await downloadAndSavePage(url);
    }
  } catch (error) {
    console.error(`Error reading CSV file: ${error.message}`);
  }
}

