#include <iostream>
#include <cmath>

class Point2D {
public:
    // Constructor
    Point2D(double x, double y) : x_(x), y_(y) {}

    // Getters
    double getX() const { return x_; }
    double getY() const { return y_; }

    // Calculate the distance between two points
    double distance(const Point2D& other) const {
        double dx = x_ - other.x_;
        double dy = y_ - other.y_;
        return std::sqrt(dx * dx + dy * dy);
    }

    // Check if three points form a triangle
    static bool isTriangle(const Point2D& p1, const Point2D& p2, const Point2D& p3) {
        double d1 = p1.distance(p2);
        double d2 = p2.distance(p3);
        double d3 = p3.distance(p1);

        return (d1 + d2 > d3) && (d1 + d3 > d2) && (d2 + d3 > d1);
    }

    // Calculate the area of the triangle formed by three points
    static double triangleArea(const Point2D& p1, const Point2D& p2, const Point2D& p3) {
        if (!isTriangle(p1, p2, p3)) {
            throw std::invalid_argument("Points do not form a triangle");
        }

        double d1 = p1.distance(p2);
        double d2 = p2.distance(p3);
        double d3 = p3.distance(p1);

        double s = (d1 + d2 + d3) / 2;
        return std::sqrt(s * (s - d1) * (s - d2) * (s - d3));
    }

private:
    double x_;
    double y_;
};

int main() {
    Point2D p1(0, 0);
    Point2D p2(3, 4);
    Point2D p3(6, 0);

    if (Point2D::isTriangle(p1, p2, p3)) {
        std::cout << "The area of the triangle is: "
                  << Point2D::triangleArea(p1, p2, p3) << std::endl;
    } else {
        std::cout << "The points do not form a triangle" << std::endl;
    }

    return 0;
}

