  let min = Infinity;
  let max = -Infinity;
  let sum = 0;
  let count = 0;

  for (let i = 0; i < arr.length; i++) {
    const num = arr[i];

    if (typeof num !== "number" || !Number.isInteger(num)) {
      throw new Error("All elements in the array must be integers");
    }

    min = Math.min(min, num);
    max = Math.max(max, num);
    sum += num;
    count++;
  }

  return {
    min: min,
    max: max,
    sum: sum,
    average: sum / count,
  };
}
