def factorial(n):
    # Check if input is a positive integer
    if not isinstance(n, int) or n < 0:
        print("Error: Input must be a positive integer.")
        return None
    # Base case for recursion (factorial of 0 and 1)
    elif n == 0 or n == 1:
        return 1
    # Recursive case
    else:
        return n * factorial(n - 1)

