class Elevator:
    def __init__(self, num_floors):
        self.current_floor = 0
        self.target_floors = []
        self.num_floors = num_floors

    def request_elevator(self, floor):
        if floor not in self.target_floors and 0 <= floor < self.num_floors:
            heapq.heappush(self.target_floors, (abs(floor - self.current_floor), floor))
            print(f"Request received for floor {floor}")

    def move_to_next_floor(self):
