#include <iostream>
#include <cmath>

class Point2D {
public:
    // Constructor
    Point2D(double x = 0, double y = 0) : x(x), y(y) {}

    // Getters and Setters
    double getX() const { return x; }
    double getY() const { return y; }

    void setX(double newX) { x = newX; }
    void setY(double newY) { y = newY; }

    // Distance between two points
    double distance(const Point2D& other) const {
        double dx = x - other.x;
        double dy = y - other.y;
        return std::sqrt(dx * dx + dy * dy);
    }

    // Midpoint between two points
    Point2D midpoint(const Point2D& other) const {
        double mx = (x + other.x) / 2;
        double my = (y + other.y) / 2;
        return Point2D(mx, my);
    }

    // Rotate point around another point by a given angle in degrees
    Point2D rotate(const Point2D& center, double angle_degrees) const {
        double angle_radians = angle_degrees * M_PI / 180.0;
        double dx = x - center.x;
        double dy = y - center.y;

        double rotated_x = dx * cos(angle_radians) - dy * sin(angle_radians);
        double rotated_y = dx * sin(angle_radians) + dy * cos(angle_radians);

        return Point2D(center.x + rotated_x, center.y + rotated_y);
    }

private:
    double x, y;
};

int main() {
    Point2D p1(3, 4);
    Point2D p2(6, 8);

    std::cout << "Distance: " << p1.distance(p2) << std::endl;

    Point2D mid = p1.midpoint(p2);
    std::cout << "Midpoint: (" << mid.getX() << ", " << mid.getY() << ")" << std::endl;

    double angle_degrees = 90;
    Point2D rotated = p1.rotate(p2, angle_degrees);
    std::cout << "Rotated by " << angle_degrees << " degrees: ("
              << rotated.getX() << ", " << rotated.getY() << ")" << std::endl;

    return 0;
}

