  console.error('Usage: node monitor.js [target_directory] [output_directory]');
  process.exit(1);
}

const targetDirectory = args[0];
const outputDirectory = args[1];

function compressFile(filePath, outputPath) {
  const gzip = zlib.createGzip();
  const inputStream = fs.createReadStream(filePath);
  const outputStream = fs.createWriteStream(outputPath);

  inputStream.pipe(gzip).pipe(outputStream);
}

function watchDirectory(directory) {
  fs.readdir(directory, { withFileTypes: true }, (err, files) => {
    if (err) {
      console.error(`Error reading directory ${directory}:`, err);
      return;
    }

    files.forEach((file) => {
      const fullPath = path.join(directory, file.name);
      if (file.isDirectory()) {
        // Recursively watch subdirectories
        watchDirectory(fullPath);
      } else {
        // Compress existing files in the directory
        const outputPath = path.join(outputDirectory, `${file.name}.gz`);
        compressFile(fullPath, outputPath);
      }
    });
  });

  fs.watch(directory, (eventType, filename) => {
    if (eventType === 'rename') {
      const filePath = path.join(directory, filename);
      fs.stat(filePath, (err, stats) => {
        if (err) {
          if (err.code === 'ENOENT') {
            // File was deleted, ignore
            return;
          }
          console.error(`Error getting file stats for ${filePath}:`, err);
          return;
        }

        if (stats.isDirectory()) {
          // Recursively watch new subdirectories
          watchDirectory(filePath);
        } else {
          const outputPath = path.join(outputDirectory, `${filename}.gz`);
          compressFile(filePath, outputPath);
        }
      });
    }
  });
}

