	topic := "text_topic"

	config := sarama.NewConfig()
	config.Consumer.Return.Errors = true
	config.Version = sarama.V2_6_0_0

	client, err := sarama.NewConsumer(kafkaBrokers, config)
	if err != nil {
		log.Fatalf("Error creating Kafka consumer: %v", err)
	}
	defer client.Close()

	ctx, cancel := context.WithCancel(context.Background())
	signals := make(chan os.Signal, 1)
	signal.Notify(signals, syscall.SIGINT, syscall.SIGTERM)
	go func() {
		<-signals
		cancel()
	}()

	consumerGroup, err := sarama.NewConsumerGroupFromClient("word_counter_group", client)
	if err != nil {
		log.Fatalf("Error creating consumer group: %v", err)
	}

	wg := &sync.WaitGroup{}
	wg.Add(1)
	go func() {
		for {
			err := consumerGroup.Consume(ctx, []string{topic}, &wordCounter{})
			if err != nil {
				log.Printf("Error consuming messages: %v", err)
			}
			if ctx.Err() != nil {
				break
			}
		}
		wg.Done()
	}()

	<-ctx.Done()
	consumerGroup.Close()
	wg.Wait()
}

type wordCounter struct{}

func (wc *wordCounter) Setup(sarama.ConsumerGroupSession) error   { return nil }
func (wc *wordCounter) Cleanup(sarama.ConsumerGroupSession) error { return nil }

func (wc *wordCounter) ConsumeClaim(sess sarama.ConsumerGroupSession, claim sarama.ConsumerGroupClaim) error {
	ctx := context.Background()
	redisClient := redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "",
		DB:       0,
	})

	for msg := range claim.Messages() {
		wordCount := countWords(string(msg.Value))
		err := storeWordCount(redisClient, ctx, string(msg.Key), wordCount)
		if err != nil {
			log.Printf("Error storing word count in Redis: %v", err)
		} else {
			fmt.Printf("Stored word count for key '%s': %d\n", msg.Key, wordCount)
