Here's an implementation of the quicksort algorithm in JavaScript, along with a demonstration of its usage on an array of numbers:

```javascript
function quickSort(arr, left = 0, right = arr.length - 1) {
  if (left < right) {
    const pivotIndex = partition(arr, left, right);

    // Recursively sort elements before and after the pivot
    quickSort(arr, left, pivotIndex - 1);
    quickSort(arr, pivotIndex + 1, right);
  }

  return arr;
}

function partition(arr, left, right) {
  const pivot = arr[right];
  let i = left;

  for (let j = left; j < right; j++) {
    if (arr[j] < pivot) {
      [arr[i], arr[j]] = [arr[j], arr[i]];
      i++;
    }
  }

  // Swap the pivot element with the element at index i
  [arr[i], arr[right]] = [arr[right], arr[i]];

  return i;
}

// Example usage:
const unsortedArray = [3, 7, 8, 5, 2, 1, 9, 6, 4];
console.log("Unsorted Array:", unsortedArray);

const sortedArray = quickSort(unsortedArray);
console.log("Sorted Array:", sortedArray);
```

