using Azure.Storage.Blobs;

class Program
{
    static string connectionString = "Your_Azure_Storage_Connection_String";
    static string containerName = "Your_Blob_Container_Name";

    static async Task Main(string[] args)
    {
        BlobServiceClient serviceClient = new BlobServiceClient(connectionString);
        BlobContainerClient containerClient = serviceClient.GetBlobContainerClient(containerName);

        // Upload file to blob
        await UploadFileAsync(containerClient, "test.txt");

        // List all blobs in the container
        await ListBlobsAsync(containerClient);

        // Download a blob
        await DownloadBlobAsync(containerClient, "test.txt");
    }

    static async Task UploadFileAsync(BlobContainerClient containerClient, string filePath)
    {
        string fileName = Path.GetFileName(filePath);
        BlobClient blobClient = containerClient.GetBlobClient(fileName);

        Console.WriteLine($"Uploading {filePath}...");
        using FileStream uploadFileStream = File.OpenRead(filePath);
        await blobClient.UploadAsync(uploadFileStream, true);
        uploadFileStream.Close();
        Console.WriteLine($"Uploaded {fileName}");
    }

    static async Task ListBlobsAsync(BlobContainerClient containerClient)
    {
        Console.WriteLine("Listing blobs...");

        await foreach (var blobItem in containerClient.GetBlobsAsync())
        {
            Console.WriteLine("\t" + blobItem.Name);
        }
    }

    static async Task DownloadBlobAsync(BlobContainerClient containerClient, string blobName)
    {
        BlobClient blobClient = containerClient.GetBlobClient(blobName);

        Console.WriteLine($"Downloading {blobName}...");
        BlobDownloadInfo download = await blobClient.DownloadAsync();

        using (FileStream downloadFileStream = File.OpenWrite(blobName))
        {
            await download.Content.CopyToAsync(downloadFileStream);
            downloadFileStream.Close();
        }
        Console.WriteLine($"Downloaded {blobName}");
    }
}
