Here's a C++ application that reads a large text file and counts the frequency of each word using an unordered_map (hash table).

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <unordered_map>
#include <sstream>
#include <algorithm>

// Function to remove punctuation from a string
std::string removePunctuation(const std::string &word) {
    std::string result;
    for (char c : word) {
        if (!ispunct(c)) {
            result += c;
        }
    }
    return result;
}

int main() {
    // Change this to your desired input file path
    std::string inputFilePath = "input.txt";

    // Open the input file
    std::ifstream inputFile(inputFilePath);
    if (!inputFile.is_open()) {
        std::cerr << "Error opening file: " << inputFilePath << std::endl;
        return 1;
    }

    // Create an unordered_map (hash table) to store word frequencies
    std::unordered_map<std::string, int> wordFrequencies;

    // Read the input file line by line
    std::string line;
    while (getline(inputFile, line)) {
        // Convert the line to lowercase
        std::transform(line.begin(), line.end(), line.begin(), ::tolower);

        // Tokenize the line into words using stringstream
        std::istringstream iss(line);
        std::string word;
        while (iss >> word) {
            // Remove punctuation from the word
            word = removePunctuation(word);

            // Increment the word count in the hash table
            wordFrequencies[word]++;
        }
    }

    // Close the input file
    inputFile.close();

    // Print the word frequencies
    for (const auto &entry : wordFrequencies) {
        std::cout << entry.first << ": " << entry.second << std::endl;
    }

    return 0;
}
```

