```javascript
const express = require('express');
const app = express();
const http = require('http').createServer(app);
const io = require('socket.io')(http);

app.use(express.static('public'));

io.on('connection', (socket) => {
  console.log('a user connected');

  socket.on('disconnect', () => {
    console.log('user disconnected');
  });

  socket.on('chat message', (msg) => {
    io.emit('chat message', msg);
  });
});

http.listen(3000, () => {
  console.log('listening on *:3000');
});
```

This code sets up an Express server that serves static files from a "public" folder and listens for incoming connections on port 3000. It also initializes Socket.IO and listens for 'connection' events, as well as 'chat message' events sent by clients.

