public class MultiThreadedDownloader {

    public static void main(String[] args) {
        if (args.length == 0) {
            System.out.println("Please provide URLs as command-line arguments.");
            return;
        }

        for (String url : args) {
            Thread downloadThread = new Thread(new FileDownloader(url));
            downloadThread.start();
        }
    }

    private static class FileDownloader implements Runnable {
        private final String url;

        public FileDownloader(String url) {
            this.url = url;
        }

        @Override
        public void run() {
            try {
                downloadFile(url);
            } catch (IOException e) {
                System.err.println("Error downloading file from " + url + ": " + e.getMessage());
            }
        }

        private void downloadFile(String urlString) throws IOException {
            URL url = new URL(urlString);
            String fileName = url.getFile().substring(url.getFile().lastIndexOf('/') + 1);

            try (BufferedInputStream in = new BufferedInputStream(url.openStream());
                 FileOutputStream out = new FileOutputStream(fileName)) {

                byte[] buffer = new byte[4096];
                int bytesRead;

                while ((bytesRead = in.read(buffer, 0, buffer.length)) != -1) {
                    out.write(buffer, 0, bytesRead);
                }

                System.out.println("Downloaded file: " + fileName);
            }
        }
    }
}

