            String name = "John Doe";
            double salary = 50000;

            employeeDatabase.createEmployee(connection, id, name, salary);
            employeeDatabase.readEmployee(connection, id);
            employeeDatabase.updateEmployee(connection, id, 60000);
            employeeDatabase.deleteEmployee(connection, id);

            employeeDatabase.closeConnection(connection);
        } catch (SQLException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    public Connection connect() throws SQLException {
        return DriverManager.getConnection(URL, USER, PASSWORD);
    }

    public void createEmployee(Connection connection, int id, String name, double salary) throws SQLException {
        String sql = "INSERT INTO employees(id, name, salary) VALUES(?, ?, ?)";
        PreparedStatement preparedStatement = connection.prepareStatement(sql);
        preparedStatement.setInt(1, id);
        preparedStatement.setString(2, name);
        preparedStatement.setDouble(3, salary);

        int rowsAffected = preparedStatement.executeUpdate();
        System.out.println(rowsAffected + " row(s) inserted.");
    }

