bool is_valid_move(vector<int> towers[3], int from, int to) {
    if (from < 0 || from >= 3 || to < 0 || to >= 3 || from == to) {
        return false;
    }

    if (towers[from].empty()) {
        return false;
    }

    if (!towers[to].empty() && towers[from].back() > towers[to].back()) {
        return false;
    }

    return true;
}

