		return
	}
	defer listener.Close()

	var wg sync.WaitGroup

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println("Error accepting connection:", err.Error())
			continue
		}

		wg.Add(1)
		go handleConnection(conn, &wg)
	}

	wg.Wait()
}

func handleConnection(conn net.Conn, wg *sync.WaitGroup) {
	defer conn.Close()
	defer wg.Done()

	reader := bufio.NewReader(conn)
	writer := bufio.NewWriter(conn)

	for {
		message, err := reader.ReadString('\n')
		if err != nil {
			if err == io.EOF {
				fmt.Printf("Client %s disconnected\n", conn.RemoteAddr().String())
			} else {
				fmt.Printf("Error reading from client %s: %v\n", conn.RemoteAddr().String(), err)
			}
			break
		}

		fmt.Printf("Received message from client %s: %s", conn.RemoteAddr().String(), message)

		_, err = writer.WriteString(message)
		if err != nil {
			fmt.Printf("Error writing to client %s: %v\n", conn.RemoteAddr().String(), err)
			break
		}

		err = writer.Flush()
		if err != nil {
			fmt.Printf("Error flushing buffer for client %s: %v\n", conn.RemoteAddr().String(), err)
			break
		}
	}
}

