class BankAccount {
private:
    int accountNumber;
    std::string accountHolderName;
    double balance;

public:
    // Constructor
    BankAccount(int accNum, std::string accHolderName, double initialBalance) {
        accountNumber = accNum;
        accountHolderName = accHolderName;
        balance = initialBalance;
    }

    // Deposit money into the account
    void deposit(double amount) {
        if (amount <= 0) {
            std::cout << "Invalid deposit amount. Please enter a positive value." << std::endl;
            return;
        }
        balance += amount;
        std::cout << "Deposit successful! New balance: $" << balance << std::endl;
    }

    // Withdraw money from the account
    void withdraw(double amount) {
        if (amount <= 0) {
            std::cout << "Invalid withdrawal amount. Please enter a positive value." << std::endl;
            return;
        }
        if (balance - amount < 0) {
            std::cout << "Insufficient funds. Cannot withdraw $" << amount << "." << std::endl;
            return;
        }
        balance -= amount;
        std::cout << "Withdrawal successful! New balance: $" << balance << std::endl;
    }

    // Display account details
    void displayAccountDetails() {
        std::cout << "Account Number: " << accountNumber << std::endl;
        std::cout << "Account Holder Name: " << accountHolderName << std::endl;
        std::cout << "Current Balance: $" << balance << std::endl;
    }
};

int main() {
