Here's a simple GoLang server that listens on a specific port, accepts incoming TCP connections, reverses the client's message, and sends it back to the client. It also handles multiple clients concurrently using Goroutines.

```go
package main

import (
	"bufio"
	"fmt"
	"net"
	"strings"
)

func reverse(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

func handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)
	for {
		message, err := reader.ReadString('\n')
		if err != nil {
			fmt.Printf("Client %s disconnected\n", conn.RemoteAddr().String())
			break
		}

		reversedMessage := reverse(strings.TrimSpace(message))
		conn.Write([]byte(reversedMessage + "\n"))
	}
}

func main() {
	port := "8080"

	listener, err := net.Listen("tcp", ":"+port)
	if err != nil {
		fmt.Println("Error starting server:", err)
		return
	}
	defer listener.Close()
	fmt.Println("Server listening on port", port)

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println("Error accepting connection:", err)
			continue
		}

		fmt.Printf("Client %s connected\n", conn.RemoteAddr().String())

		go handleConnection(conn)
	}
}
