#include <unordered_map>

int tsp(int pos, int visited, const std::vector<std::vector<int>>& dist,
        std::unordered_map<int, std::unordered_map<int, int>>& memo) {
    if (visited == ((1 << dist.size()) - 1)) {
        return dist[pos][0];
    }

    if (memo.find(pos) != memo.end() && memo[pos].find(visited) != memo[pos].end()) {
        return memo[pos][visited];
    }

    int min_dist = std::numeric_limits<int>::max();
    for (int i = 0; i < dist.size(); ++i) {
        if (!(visited & (1 << i))) {
            int new_visited = visited | (1 << i);
            int cur_dist = dist[pos][i] + tsp(i, new_visited, dist, memo);
            min_dist = std::min(min_dist, cur_dist);
        }
    }

    memo[pos][visited] = min_dist;
    return min_dist;
}

int main() {
    int n;
    std::cin >> n;

    std::vector<std::vector<int>> dist(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
