Here's a simple HTTP server in C++ using Boost.Asio library. This example serves static files from the specified directory and listens on the given port.

First, make sure you have installed the Boost libraries. You can download them from https://www.boost.org/users/download/ or install via package manager (e.g., `sudo apt-get install libboost-all-dev` for Ubuntu).

Create a file named `http_server.cpp` and paste the following code:

```cpp
#include <boost/asio.hpp>
#include <boost/filesystem.hpp>
#include <iostream>
#include <fstream>
#include <string>

using boost::asio::ip::tcp;

std::string get_content_type(const std::string& ext) {
    if (ext == ".html" || ext == ".htm") return "text/html";
    if (ext == ".css") return "text/css";
    if (ext == ".js") return "application/javascript";
    if (ext == ".jpg" || ext == ".jpeg") return "image/jpeg";
    if (ext == ".png") return "image/png";
    if (ext == ".gif") return "image/gif";
    return "application/octet-stream";
}

void handle_request(tcp::socket& socket, const std::string& root_dir) {
    boost::system::error_code ec;
    boost::asio::streambuf request_buf;
    boost::asio::read_until(socket, request_buf, "\r\n\r\n", ec);
    if (ec) return;

    std::istream request_stream(&request_buf);
    std::string method, uri, version;
    request_stream >> method >> uri >> version;

    std::string path = root_dir + uri;
    if (path.back() == '/') path += "index.html";

    boost::filesystem::path fs_path(path);
    if (!boost::filesystem::exists(fs_path)) {
        std::string response = "HTTP/1.0 404 Not Found\r\nContent-Length: 0\r\n\r\n";
        boost::asio::write(socket, boost::asio::buffer(response), ec);
        return;
    }

    std::ifstream file(path, std::ios::binary | std::ios::ate);
    if (!file) {
        std::string response = "HTTP/1.0 500 Internal Server Error\r\nContent-Length: 0\r\n\r\n";
        boost::asio::write(socket, boost::asio::buffer(response), ec);
        return;
    }

    size_t file_size = file.tellg();
    file.seekg(0);

    std::string content_type = get_content_type(fs_path.extension().string());
    std::string response_header = "HTTP/1.0 200 OK\r\nContent-Type: " + content_type +
                                  "\r\nContent-Length: " + std::to_string(file_size) + "\r\n\r\n";

    boost::asio::write(socket, boost::asio::buffer(response_header), ec);
    if (ec) return;

    constexpr size_t buffer_size = 8192;
    char buffer[buffer_size];
    while (file.read(buffer, buffer_size)) {
        boost::asio::write(socket, boost::asio::buffer(buffer, file.gcount()), ec);
        if (ec) break;
    }
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: http_server <port> <root_dir>\n";
        return 1;
    }

    unsigned short port = static_cast<unsigned short>(std::stoi(argv[1]));
    std::string root_dir = argv[2];

    try {
        boost::asio::io_context io_context;
        tcp::acceptor acceptor(io_context, tcp::endpoint(tcp::v4(), port));

        for (;;) {
            tcp::socket socket(io_context);
            acceptor.accept(socket);
            handle_request(socket, root_dir);
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }

    return 0;
}
