```java
import java.util.ArrayList;
import java.util.List;

class Book {
    private String title;
    private String author;
    private String isbnNumber;

    public Book(String title, String author, String isbnNumber) {
        this.title = title;
        this.author = author;
        this.isbnNumber = isbnNumber;
    }

    // getters and setters
    public String getTitle() { return title; }
    public String getAuthor() { return author; }
    public String getIsbnNumber() { return isbnNumber; }
}

class Member {
    private String name;
    private String membershipId;
    private List<Book> borrowedBooks;

    public Member(String name, String membershipId) {
        this.name = name;
        this.membershipId = membershipId;
        this.borrowedBooks = new ArrayList<>();
    }

    // methods to issue and return books
    public void borrowBook(Book book) {
        borrowedBooks.add(book);
    }

    public void returnBook(Book book) {
        borrowedBooks.remove(book);
    }

    // getters and setters
    public String getName() { return name; }
    public String getMembershipId() { return membershipId; }
    public List<Book> getBorrowedBooks() { return borrowedBooks; }
}

public class LibraryManagementSystem {
    public static void main(String[] args) {
        // create new member
        Member member1 = new Member("John Doe", "M001");

        // create new books
        Book book1 = new Book("The Great Gatsby", "F. Scott Fitzgerald", "9780743273565");
        Book book2 = new Book("To Kill a Mockingbird", "Harper Lee", "9780060935467");

        // member borrows books
        member1.borrowBook(book1);
        member1.borrowBook(book2);

        System.out.println(member1.getName() + " has borrowed: ");
        for (Book book : member1.getBorrowedBooks()) {
            System.out.println("- " + book.getTitle());
        }

        // member returns a book
        member1.returnBook(book1);

        System.out.println("\nAfter returning a book, " + member1.getName() + " has borrowed: ");
        for (Book book : member1.getBorrowedBooks()) {
            System.out.println("- " + book.getTitle());
        }
    }
}
```

