public class GameOfLife {
    private int[][] board;

    public GameOfLife(int[][] initialBoard) {
        this.board = initialBoard;
    }

    public void play() {
        while (true) {
            printBoard();
            int[][] nextGeneration = getNextGeneration();

            if (isSameBoard(board, nextGeneration)) {
                break;
            }

            board = nextGeneration;
        }
    }

    private void printBoard() {
        for (int[] row : board) {
            for (int cell : row) {
                System.out.print(cell + " ");
            }
            System.out.println();
        }
        System.out.println();
    }

    private int[][] getNextGeneration() {
        int rows = board.length;
        int cols = board[0].length;
        int[][] nextGeneration = new int[rows][cols];

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                int aliveNeighbours = countAliveNeighbours(i, j);

                if (board[i][j] == 1 && (aliveNeighbours < 2 || aliveNeighbours > 3)) {
                    nextGeneration[i][j] = 0;
                } else if (board[i][j] == 0 && aliveNeighbours == 3) {
                    nextGeneration[i][j] = 1;
                } else {
                    nextGeneration[i][j] = board[i][j];
                }
            }
        }

        return nextGeneration;
    }

    private int countAliveNeighbours(int row, int col) {
        int count = 0;
        for (int i = Math.max(0, row - 1); i <= Math.min(row + 1, board.length - 1); i++) {
            for (int j = Math.max(0, col - 1); j <= Math.min(col + 1, board[0].length - 1); j++) {
                count += board[i][j];
            }
        }
        count -= board[row][col];
        return count;
    }

    private boolean isSameBoard(int[][] board1, int[][] board2) {
        for (int i = 0; i < board1.length; i++) {
            for (int j = 0; j < board1[0].length; j++) {
                if (board1[i][j] != board2[i][j]) {
                    return false;
                }
            }
        }
        return true;
    }
}

