        sum += number;
    }
    return sum / numbers.size();
}

double calculate_median(std::vector<double> numbers) {
    size_t size = numbers.size();
    std::sort(numbers.begin(), numbers.end());
    if (size % 2 == 0) {
        return (numbers[size / 2 - 1] + numbers[size / 2]) / 2;
    } else {
        return numbers[size / 2];
    }
}

std::vector<double> calculate_mode(const std::vector<double>& numbers) {
    std::map<double, int> counts;
    for (const auto& number : numbers) {
        counts[number]++;
    }

    int max_count = 0;
    for (const auto& element : counts) {
        max_count = std::max(max_count, element.second);
    }

    std::vector<double> modes;
    for (const auto& element : counts) {
        if (element.second == max_count) {
            modes.push_back(element.first);
        }
    }

    return modes;
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " input_file output_file" << std::endl;
        return 1;
    }

    std::ifstream input_file(argv[1]);
    if (!input_file.is_open()) {
        std::cerr << "Error opening input file." << std::endl;
        return 1;
    }

    std::ofstream output_file(argv[2]);
    if (!output_file.is_open()) {
        std::cerr << "Error opening output file." << std::endl;
        return 1;
    }

    std::vector<double> numbers;
    double number;
    while (input_file >> number) {
        numbers.push_back(number);
    }

    double mean = calculate_mean(numbers);
    double median = calculate_median(numbers);
    std::vector<double> mode = calculate_mode(numbers);

    std::cout << "Mean: " << mean << std::endl;
    std::cout << "Median: " << median << std::endl;
    std::cout << "Mode:";
    for (const auto& m : mode) {
        std::cout << " " << m;
    }
    std::cout << std::endl;

    output_file << "Mean: " << mean << std::endl;
    output_file << "Median: " << median << std::endl;
    output_file << "Mode:";
    for (const auto& m : mode) {
        output_file << " " << m;
    }
    output_file << std::endl;

    input_file.close();
    output_file.close();

    return 0;
}
