#include <stdexcept>

class Stack {
private:
    static const int MAX_SIZE = 10;
    int arr[MAX_SIZE];
    int top;

public:
    // Constructor initializes the top variable to -1, indicating that the stack is empty
    Stack() : top(-1) {}

    // Push function checks if the stack is full before adding an element
    void push(int value) {
        if (top >= MAX_SIZE - 1) {
            throw std::overflow_error("Stack Overflow");
        }
        arr[++top] = value;
    }

    // Pop function checks if the stack is empty before removing an element
    int pop() {
        if (top < 0) {
            throw std::underflow_error("Stack Underflow");
        }
        return arr[top--];
    }

    // Peek function checks if the stack is empty before returning the top element
    int peek() const {
        if (top < 0) {
            throw std::underflow_error("Stack Underflow");
        }
        return arr[top];
    }

    // Function to check if the stack is empty
    bool isEmpty() const {
        return top == -1;
    }
};

