To create a TypeScript application that reads data from a CSV file, processes it, and writes the output to a new CSV file, you'll need to follow these steps:

1. Install Node.js and npm (if not already installed).
2. Create a new directory for your project and navigate to it in the terminal.
3. Run `npm init` to create a package.json file.
4. Install necessary dependencies: `npm install typescript csv-parser csv-writer @types/node --save`
5. Initialize a TypeScript configuration file by running `npx tsc --init`.
6. Create an input.csv file with some sample data.

For example, let's use this simple dataset:

```
id,name,age
1,Alice,30
2,Bob,25
3,Charlie,22
4,Diana,28
```

7. Create a main.ts file and add the following code:

```typescript
import * as fs from 'fs';
import * as csvParser from 'csv-parser';
import { createObjectCsvWriter as createCsvWriter } from 'csv-writer';

interface Person {
  id: string;
  name: string;
  age: string;
}

const readCSV = async (filePath: string): Promise<Person[]> => {
  const rows: Person[] = [];

  return new Promise((resolve, reject) => {
    fs.createReadStream(filePath)
      .pipe(csvParser())
      .on('data', (row: Person) => rows.push(row))
      .on('end', () => resolve(rows))
      .on('error', (err) => reject(err));
  });
};

const writeCSV = async (filePath: string, data: Person[]): Promise<void> => {
  const csvWriter = createCsvWriter({
    path: filePath,
    header: [
      { id: 'id', title: 'ID' },
      { id: 'name', title: 'NAME' },
      { id: 'age', title: 'AGE' },
    ],
  });

  return csvWriter.writeRecords(data);
};

const processCSV = async (inputFile: string, outputFile: string): Promise<void> => {
  try {
    const data = await readCSV(inputFile);

    // Filter rows based on a given condition
    const filteredData = data.filter((row) => parseInt(row.age) >= 25);

    // Sort rows based on a specific column
    const sortedData = filteredData.sort((a, b) => parseInt(a.age) - parseInt(b.age));

    await writeCSV(outputFile, sortedData);
    console.log('Output file created successfully');
  } catch (err) {
    console.error('Error processing CSV:', err);
  }
};

// Replace with the path to your input and output files
const inputFile = './input.csv';
const outputFile = './output.csv';

processCSV(inputFile, outputFile);
```

