To create a Node.js Express server with the required endpoints, you'll need to install some dependencies:

1. Install `express` for creating the server.
2. Install `multer` for handling file uploads.
3. Install `crypto` for generating MD5 hashes.

Run this command in your terminal to install these packages:

```bash
npm install express multer crypto
```

Now, create a new file called `app.js` and add the following code:

```javascript
const express = require('express');
const multer = require('multer');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const app = express();
const upload = multer({ limits: { fileSize: 500 * 1024 } }); // Limit file size to 500 KB

// Create directory for storing images if it doesn't exist
const imageDir = 'images';
if (!fs.existsSync(imageDir)) {
  fs.mkdirSync(imageDir);
}

// Function to generate MD5 hash of a file
function md5File(file) {
  const buffer = fs.readFileSync(file.path);
  return crypto.createHash('md5').update(buffer).digest('hex');
}

// Upload endpoint
app.post('/upload', upload.single('image'), (req, res) => {
  if (!req.file) {
    return res.status(400).send('No file uploaded.');
  }

  const allowedMimeTypes = ['image/jpeg', 'image/png'];
  if (!allowedMimeTypes.includes(req.file.mimetype)) {
    fs.unlinkSync(req.file.path); // Delete the temporary file
    return res.status(400).send('Invalid file type. Only JPEG and PNG are allowed.');
  }

  const md5hash = md5File(req.file);
  const ext = path.extname(req.file.originalname);
  const newPath = path.join(imageDir, md5hash + ext);

  fs.renameSync(req.file.path, newPath); // Move the temporary file to the new path
  res.send({ id: md5hash });
});

// Retrieve image endpoint
app.get('/image/:id', (req, res) => {
  const { id } = req.params;
  const imagePathJpeg = path.join(imageDir, id + '.jpeg');
  const imagePathPng = path.join(imageDir, id + '.png');

  if (fs.existsSync(imagePathJpeg)) {
    res.sendFile(path.resolve(imagePathJpeg));
  } else if (fs.existsSync(imagePathPng)) {
    res.sendFile(path.resolve(imagePathPng));
  } else {
    res.status(404).send('Image not found.');
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => console.log(`Server running on port ${port}`));
```

This code creates an Express server with two endpoints:

1. `/upload`: This endpoint accepts a POST request with a single file named `image`. It checks if the file is a JPEG or PNG and has a size of less than 500 KB. If the conditions are met, it generates an MD5 hash for the file and stores it in the `images` directory.

2. `/image/:id`: This endpoint accepts a GET request with an ID parameter. It looks for an image with the given ID (MD5 hash) in the `images` directory and sends it as a response if found. Otherwise, it returns a 404 status with an "Image not found" message.

To run the server, execute this command in your terminal:

```bash
node app.js
```

